import{_ as t,o as a,c as _,ai as r}from"./chunks/framework.B1-4-q7d.js";const f=JSON.parse('{"title":"科技如何赋能春耕生产跑出“加速度”？ 这场现场会上“干货”多","description":"","frontmatter":{"sidebar":false,"aside":false,"editLink":false,"lastUpdated":false,"prev":false,"next":false,"title":"科技如何赋能春耕生产跑出“加速度”？ 这场现场会上“干货”多","date":"2026-04-23T00:00:00.000Z","source":"中国农业信息网","category":"news","link":"https://www.agri.cn/zt/zhzz/zxdt/202604/t20260423_8830757.htm","summary":"4月14日至15日，浙江省粮油作物大面积单产提升暨早稻生产现场会在诸暨召开。科技如何赋能春耕生产跑出“加速度”、全力推动粮油作物大面积单产提升和早稻生产？这个现场会带来很多“干货”。\\n现场会上，田间地头展示的“科技春耕图”让与会代表们眼前一亮。在诸暨市山下湖镇新桔城省级粮食生产功能区，高速插秧机、行走式插秧机在田间来回穿梭、匀速作业，一株株秧苗被整齐均匀地插入水田。...\\n","contentHash":"181e15f9969f3049d19dbd400fe13d62","tags":["智慧农业","行业资讯"]},"headers":[],"relativePath":"news/2026-04-23-科技如何赋能春耕生产跑出-加速度-这场现场会上-干货-多.md","filePath":"news/2026-04-23-科技如何赋能春耕生产跑出-加速度-这场现场会上-干货-多.md"}'),s={name:"news/2026-04-23-科技如何赋能春耕生产跑出-加速度-这场现场会上-干货-多.md"};function n(o,e,p,l,d,i){return a(),_("div",null,[...e[0]||(e[0]=[r('<h1 id="科技如何赋能春耕生产跑出-加速度-这场现场会上-干货-多" tabindex="-1">科技如何赋能春耕生产跑出“加速度”？ 这场现场会上“干货”多 <a class="header-anchor" href="#科技如何赋能春耕生产跑出-加速度-这场现场会上-干货-多" aria-label="Permalink to &quot;科技如何赋能春耕生产跑出“加速度”？ 这场现场会上“干货”多&quot;">​</a></h1><blockquote><p>来源: <a href="https://www.agri.cn/zt/zhzz/zxdt/202604/t20260423_8830757.htm" target="_blank" rel="noreferrer">中国农业信息网</a><br> 日期: 2026-04-23 摘要: 4月14日至15日，浙江省粮油作物大面积单产提升暨早稻生产现场会在诸暨召开。科技如何赋能春耕生产跑出“加速度”、全力推动粮油作物大面积单产提升和早稻生产？这个现场会带来很多“干货”。 现场会上，田间地头展示的“科技春耕图”让与会代表们眼前一亮。在诸暨市山下湖镇新桔城省级粮食生产功能区，高速插秧机、行走式插秧机在田间来回穿梭、匀速作业，一株株秧苗被整齐均匀地插入水田。...</p></blockquote><p>4月14日至15日，浙江省粮油作物大面积单产提升暨早稻生产现场会在诸暨召开。科技如何赋能春耕生产跑出“加速度”、全力推动粮油作物大面积单产提升和早稻生产？这个现场会带来很多“干货”。</p><p>现场会上，田间地头展示的“科技春耕图”让与会代表们眼前一亮。在诸暨市山下湖镇新桔城省级粮食生产功能区，高速插秧机、行走式插秧机在田间来回穿梭、匀速作业，一株株秧苗被整齐均匀地插入水田。该功能区机械作业率达98%以上，是我省农业“双强”行动的生动样本。在诸暨市农业发展现代农事服务中心内，农机精准作业平台引人注目，插秧机搭载的北斗导航终端系统，可实时记录作业面积、行动轨迹，并将数据回传至系统终端，便于农户和主管部门精准统计、掌握早稻机插进度。</p><p>田间地头的高效作业，离不开“云端”的数字大脑支撑。现场会上，“浙农粮”应用成为与会代表关注的焦点。据了解，该应用聚焦粮食生产“耕、种、管、收”全过程，协同“浙农田”“浙农机”“浙农技”“浙农经管”“惠农直通车”等应用，以资金流贯通业务流和数据流，提升粮食安全“一网统管”、粮食生产“一网协同”智能化水平。目前，系统注册用户达3.5万人，入库规模主体2.38万家，今年累计访问量达130万次。</p><p>记者从会上获悉，当前，我省春耕生产有序推进。今年全省计划种植早稻216.2万亩，截至4月15日，已育秧142万亩、栽插87万亩。全省冬种小麦有310.6万亩、油菜215.7万亩，大部分小麦处于抽穗扬花期、油菜处于角果期，正是产量形成的关键节点，也是春季管理关键期。</p><p>省农业农村厅相关负责人说，各地要深入推进春季农业生产，打好全年粮油生产“第一仗”。深入实施粮油作物大面积单产提升行动，全要素集成、分作物实施、分区域推进，千方百计稳水稻、“五良”融合提单产、进村入户优服务、环环紧扣减损失，不断挖掘释放大面积增产潜力。深入推进粮油产业高质量发展，统筹抓好粮食单产和品质双提升，在优化扶持政策、强化数字赋能、创新经营模式、提升主体素质、推行绿色生产等方面持续发力，着力提升种粮综合效益，促进农民增收致富。（农村信息报记者 沈璐兰）</p><p><a href="https://www.agri.cn/zt/zhzz/zxdt/202604/t20260423_8830757.htm" target="_blank" rel="noreferrer">阅读原文</a></p>',8)])])}const h=t(s,[["render",n]]);export{f as __pageData,h as default};
